import{_ as i,c as a,o as t,aN as e}from"./chunks/framework.CqA5BTDU.js";const c=JSON.parse('{"title":"权限管理","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/05-权限管理.md","filePath":"01.Linux基础/05-权限管理.md","lastUpdated":null}'),d={name:"01.Linux基础/05-权限管理.md"};function h(n,s,p,l,o,k){return t(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="权限管理" tabindex="-1">权限管理 <a class="header-anchor" href="#权限管理" aria-label="Permalink to &quot;权限管理&quot;">​</a></h1><p>Linux 的文件访问控制以 UGO（user/group/other）为基础，按需配合 ACL、特殊权限位和扩展属性。</p><h2 id="一、ugo-权限模型" tabindex="-1">一、UGO 权限模型 <a class="header-anchor" href="#一、ugo-权限模型" aria-label="Permalink to &quot;一、UGO 权限模型&quot;">​</a></h2><p>每个文件有三组权限，分别对应三类身份：</p><table tabindex="0"><thead><tr><th>身份</th><th>含义</th></tr></thead><tbody><tr><td>User（owner）</td><td>文件的所有者</td></tr><tr><td>Group</td><td>文件所属组的成员</td></tr><tr><td>Other</td><td>既不是 owner 也不属于 group 的所有人</td></tr></tbody></table><p>权限判断的顺序是 owner → group → other，命中即停。这意味着：即使属于文件 group 且有组权限，如果自己就是 owner，那只看 owner 权限位，group 部分被跳过。</p><p>另一个容易被忽略的规则：访问文件需要路径上<strong>每一级目录</strong>都有 <code>x</code>（执行）权限。目录没有 <code>x</code>，就算文件本身权限是 777 也进不去。</p><p><code>ls -l</code> 的输出：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-rw-r----- 1 nginx adm 1024 May 21 10:00 app.log</span></span></code></pre></div><p>逐段拆开：</p><table tabindex="0"><thead><tr><th>部分</th><th>含义</th></tr></thead><tbody><tr><td><code>-</code></td><td>文件类型，<code>-</code> 表示普通文件</td></tr><tr><td><code>rw-</code></td><td>owner（nginx）有读和写权限</td></tr><tr><td><code>r--</code></td><td>group（adm）只有读权限</td></tr><tr><td><code>---</code></td><td>other 没有任何权限</td></tr><tr><td><code>nginx</code></td><td>文件所有者</td></tr><tr><td><code>adm</code></td><td>文件所属组</td></tr></tbody></table><p>权限位对文件和目录的意义不同：</p><table tabindex="0"><thead><tr><th>权限</th><th>作用于文件</th><th>作用于目录</th></tr></thead><tbody><tr><td><code>r</code>（读）</td><td>查看文件内容</td><td>列出目录中的文件名（<code>ls</code> 可行）</td></tr><tr><td><code>w</code>（写）</td><td>修改文件内容</td><td>在目录中创建、删除、重命名文件</td></tr><tr><td><code>x</code>（执行）</td><td>作为程序运行</td><td>进入目录（<code>cd</code> 可行）</td></tr></tbody></table><p>目录的 <code>w</code> 权限要特别注意：有 <code>w</code> 权限就能删除目录中的<strong>任何</strong>文件，即使这个文件不属于自己（前提是目录的 <code>w</code> 权限对自己开放）。<code>/tmp</code> 就是典型——每个人都能在里面创建文件，也能删别人的文件，所以 <code>/tmp</code> 一般会加 Sticky Bit 限制删除权限。</p><h2 id="二、chmod-修改权限" tabindex="-1">二、chmod 修改权限 <a class="header-anchor" href="#二、chmod-修改权限" aria-label="Permalink to &quot;二、chmod 修改权限&quot;">​</a></h2><p>数字模式用三位八进制数表示权限。<code>r=4</code>、<code>w=2</code>、<code>x=1</code>，相加组合。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 644</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # owner 读写，其余只读</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # owner 全权限，其余读+执行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 750</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # owner 和 group 可用，other 无权限</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> private.key</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 仅 owner 读写</span></span></code></pre></div><table tabindex="0"><thead><tr><th>八进制</th><th>组合</th><th>权限含义</th></tr></thead><tbody><tr><td>7</td><td>4+2+1</td><td>读+写+执行</td></tr><tr><td>6</td><td>4+2</td><td>读+写</td></tr><tr><td>5</td><td>4+1</td><td>读+执行</td></tr><tr><td>0</td><td>—</td><td>无权限</td></tr></tbody></table><p>符号模式适合做增量修改：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u+x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # owner 加执行权限</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g+w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shared-dir</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # group 加写权限</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> o-r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # other 去掉读权限</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 所有身份加执行（等同 a+x）</span></span></code></pre></div><p>私钥文件（SSH key、TLS 密钥）、含密码的配置文件，权限至少 <code>600</code>。权限过宽（如 644、777）时，某些服务（如 sshd）会拒绝使用并报错。</p><h2 id="三、chown-修改所有者" tabindex="-1">三、chown 修改所有者 <a class="header-anchor" href="#三、chown-修改所有者" aria-label="Permalink to &quot;三、chown 修改所有者&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chown</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:nginx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/nginx/access.log</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app:app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 递归修改</span></span></code></pre></div><p><code>chown -R</code> 和 <code>chmod -R</code> 的递归会影响整个目录树。路径打错时破坏面很大——特别是 <code>/etc</code>、<code>/var</code> 等系统目录。执行前先 <code>pwd</code> 加 <code>ls -ld</code> 确认。</p><h2 id="四、umask-默认权限" tabindex="-1">四、umask 默认权限 <a class="header-anchor" href="#四、umask-默认权限" aria-label="Permalink to &quot;四、umask 默认权限&quot;">​</a></h2><p><code>umask</code> 决定新建文件和目录时，默认减掉哪些权限位。它不直接设置权限，而是设置一个&quot;掩码&quot;——从满权限里扣除。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">umask</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 查看当前值</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">umask</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 022</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 设置为 022</span></span></code></pre></div><p>常见默认结果：</p><table tabindex="0"><thead><tr><th>umask</th><th>新建文件实际权限</th><th>新建目录实际权限</th></tr></thead><tbody><tr><td><code>022</code></td><td><code>644</code>（rw-r--r--）</td><td><code>755</code>（rwxr-xr-x）</td></tr><tr><td><code>027</code></td><td><code>640</code>（rw-r-----）</td><td><code>750</code>（rwxr-x---）</td></tr><tr><td><code>077</code></td><td><code>600</code>（rw-------）</td><td><code>700</code>（rwx------）</td></tr></tbody></table><p>注意新建文件默认不会得到执行权限（<code>x</code>），因为大多数文件不需要可执行。服务进程创建出来的日志文件权限与预期不符时，除了检查程序代码中的权限设置，也要看启动用户的 <code>umask</code>。</p><h2 id="五、acl-访问控制列表" tabindex="-1">五、ACL 访问控制列表 <a class="header-anchor" href="#五、acl-访问控制列表" aria-label="Permalink to &quot;五、ACL 访问控制列表&quot;">​</a></h2><p>UGO 只能表达三类身份。当需要&quot;文件属于 app 组，但同时让 deploy 用户有只读权限&quot;这种例外时，ACL 可以单独授权。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getfacl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 查看文件 ACL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setfacl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u:deploy:r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 给 deploy 用户加只读</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setfacl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g:ops:rx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 给 ops 组加读和执行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setfacl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u:deploy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 删除 deploy 用户的 ACL 条目</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setfacl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 清空所有 ACL，回到纯 UGO</span></span></code></pre></div><p>ACL 适合少量例外场景。如果系统里到处在用 ACL 管理权限，排查时只看 <code>ls -l</code> 会漏掉很多信息，维护成本上升很快。</p><h2 id="六、suid、sgid、sticky-bit" tabindex="-1">六、SUID、SGID、Sticky Bit <a class="header-anchor" href="#六、suid、sgid、sticky-bit" aria-label="Permalink to &quot;六、SUID、SGID、Sticky Bit&quot;">​</a></h2><p>这三个特殊权限位在 <code>ls -l</code> 中会替代通常的 <code>x</code> 位置显示。</p><p><strong>SUID（Set UID）</strong>：文件执行时，进程临时获得文件 owner 的权限。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/bin/passwd</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -rwsr-xr-x  注意 owner 权限位中的 s</span></span></code></pre></div><p><code>/usr/bin/passwd</code> 是典型例子：普通用户执行它时要修改 <code>/etc/shadow</code>（仅 root 可写），靠 SUID 临时提权完成。SUID 权限安全风险较高，系统中出现的 SUID 文件都应该被确认是预期的。</p><p><strong>SGID（Set GID）</strong>：设在目录上时，该目录下新建的文件自动继承目录的所属组，而非创建者的主组。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g+s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shared-dir</span></span></code></pre></div><p>多人协作的共享目录常用 SGID，确保所有人创建的文件都属于同一个组。</p><p><strong>Sticky Bit</strong>：设在目录上时，只有文件 owner、目录 owner 和 root 能删除目录中的文件，其他人即使有目录写权限也不能删别人的文件。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ld</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># drwxrwxrwt  注意 other 权限位中的 t</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shared-dir</span></span></code></pre></div><p><code>/tmp</code> 设了 Sticky Bit——所有用户都能在里面创建临时文件，但不能删除别人的文件。</p><h2 id="七、chattr-扩展属性" tabindex="-1">七、chattr 扩展属性 <a class="header-anchor" href="#七、chattr-扩展属性" aria-label="Permalink to &quot;七、chattr 扩展属性&quot;">​</a></h2><p><code>chattr</code> 设置的属性作用于文件系统层面，比普通权限更底层。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chattr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> important.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 设为不可修改（immutable）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsattr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> important.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 查看扩展属性</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> important.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 去掉不可修改属性</span></span></code></pre></div><p><code>+i</code>（immutable）之后，即便是 root 用户也不能修改、删除、重命名该文件，也不能创建硬链接。必须先 <code>chattr -i</code> 去掉属性才能操作。</p><p>另一个有用的属性是 <code>+a</code>（append only）：只允许向文件追加内容，不能覆盖已有内容，适合保护日志文件不被误删。</p><p>线上遇到过的情况：自动化部署脚本修改配置文件失败，排查很久才发现配置文件被加了 <code>+i</code> 属性——可能是之前某次临时加固时设的，后来忘了去掉。所以改不动文件时，<code>lsattr</code> 值得一看。</p>`,51)])])}const g=i(d,[["render",h]]);export{c as __pageData,g as default};
